.container {
    position: relative; /* 相对定位，用于包含视频 */
    height: 100%; /* 容器高度与视频原始高度相同 */
    overflow: hidden; /* 隐藏超出容器的部分 */
}
.title {
    position: absolute; /* 绝对定位，相对于容器 */
    top: 0; 
    width: 100%;
    overflow: hidden; 
    text-overflow: ellipsis;
    display: -webkit-box;
    -webkit-box-orient: vertical; 
    -webkit-line-clamp: 2;
    z-index: 1; /* 确保标题在视频之上 */
    background: #000; /* 纯黑色背景 */ 
    padding: 0 0 3px 0;
}
video {
    position: absolute; /* 绝对定位，相对于容器 */ 
    top: +20px; /* 视频上移 */
    left: 0; 
    width: 100%; 
    height: calc(93% + 0px);  /* 调整高度以适应内容 */
    object-fit: contain; /* 确保视频内容不被裁剪 */
    z-index: 0; /* 确保视频在标题之下 */
