for (var i = 0; i < sources.length; i++) {
    // 检查源是否为空（去除空格后判断）
    if (sources[i] && sources[i].trim() !== '') {
        validSources.push(i);
    }
}

// 只有当有效源数量大于1时才显示按钮
if (validSources.length > 1) {
