result=`
<html>  
<head>  
<meta charset="utf-8">  
<meta name="viewport" content="width=device-width,initial-scale=1,minimum-scale=1,maximum-scale=1,user-scalable=no">
<meta name="referrer" content="never"/>
<script src="https://s4.zstatic.net/ajax/libs/hls.js/1.6.13/hls.min.js"></script>
<style>
html, body { margin: 0; padding: 0; width: 100%; overflow: hidden; }
.source-container { position: absolute; top: 23px; right: 1px; z-index: 10; display: flex; gap: 1px; }
.source-btn { color: #ff0; background: rgba(0,0,0,0.7); padding: 1px 5px; border-radius: 10px; font-size: 13px; border: none; cursor: pointer; }
.source-btn.active { color: red !important; }
</style>
</head>  
<body>  
<div class="container">
    <div class="title"><span>{{@@title@text##- J163视频}}</span></div>
    ${sourceButtons ? `<div class="source-container">${sourceButtons}</div>` : ''}
    <video id="video" width="100%" height="91%" poster="{{@@script@all##preview_url: '(.*?)',##$1##}}" controls autoplay muted loop></video>
<script>
    const video = document.getElementById('video');
    const sources = ${JSON.stringify(sources)};
    const validSources = ${JSON.stringify(validSources)}; // 有效源的索引数组
    let hls = null;
    let currentSource = 0;

    // 初始化HLS播放
    function playHLS(url) {
        if (hls) hls.destroy();

        if (Hls.isSupported()) {
            hls = new Hls({
                enableSoftwareAES: true,
                maxBufferLength: 30,
                maxMaxBufferLength: 60
            });

            // 添加错误监听
            hls.on(Hls.Events.ERROR, function(event, data) {
                if (data.fatal) {
                    switchToNextSource();
                }
            });

            hls.loadSource(url);
            hls.attachMedia(video);
        } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
            video.src = url;
        }

        // 视频元素错误监听
        video.onerror = function() {
            switchToNextSource();
        };
    }

    // 获取下一个有效源索引
    function getNextValidSourceIndex() {
        if (validSources.length <= 1) return currentSource;

        const currentIndex = validSources.indexOf(currentSource);
        if (currentIndex === -1) return validSources[0];

        const nextIndex = (currentIndex + 1) % validSources.length;
        return validSources[nextIndex];
    }

    // 切换到下一个有效源
    function switchToNextSource() {
        if (validSources.length <= 1) return;

        currentSource = getNextValidSourceIndex();
        playHLS(sources[currentSource]);
        updateButtons();
    }

    // 切换视频源
    function switchSource(index) {
        // 确保索引有效且源不为空
        if (validSources.includes(index) && sources[index] && sources[index].trim() !== '') {
            currentSource = index;
            playHLS(sources[index]);
            updateButtons();
        }
    }

    // 更新按钮状态
    function updateButtons() {
        document.querySelectorAll('.source-btn').forEach(btn => {
            const index = parseInt(btn.dataset.index);
            btn.classList.toggle('active', index === currentSource);
        });
    }

    // 获取第一个有效源
    function getFirstValidSource() {
        for (let i = 0; i < sources.length; i++) {
            if (sources[i] && sources[i].trim() !== '') {
                return i;
            }
        }
        return 0; // 如果没有有效源，返回0
    }

    // 监听播放结束事件
    video.onended = function() {
        if (validSources.length === 1) {
            // 单源循环播放
            video.currentTime = 0;
            video.play();
        } else {
            // 多源顺序播放
            switchToNextSource();
        }
    };

    // 绑定按钮事件
    document.querySelectorAll('.source-btn').forEach(btn => {
        btn.addEventListener('click', () => switchSource(parseInt(btn.dataset.index)));
    });

    // 播放第一个有效源
    const firstValidSource = getFirstValidSource();
    if (sources.length > 0 && sources[firstValidSource]) {
        currentSource = firstValidSource;
        switchSource(firstValidSource);
    }
</script>

</div>
</body>  
</html>
`;

