<meta charset="utf-8">  
<meta name="viewport" content="width=device-width,initial-scale=1,minimum-scale=1,maximum-scale=1,user-scalable=no">
<meta name="referrer" content="never"/>
<script src="https://s4.zstatic.net/ajax/libs/hls.js/1.6.13/hls.min.js"></script>
<style>
html, body { text-align: center; margin: 0; padding: 0; width: 100%; overflow: hidden; }
.source-container { position: absolute; top: 23px; right: 1px; z-index: 10; display: flex; gap: 1px; }
.source-btn { color: #ff0; background: rgba(0,0,0,0.7); padding: 1px 5px; border-radius: 10px; font-size: 13px; border: none; cursor: pointer; }
.source-btn.active { color: red !important; }
</style>
</head>  
<body>  
<div class="container">
    <div class="title">{{@@title@text## / Embed Player}}</div>
    ${sources.length > 1 ? `<div class="source-container">${sourceButtons}</div>` : ''}
    <video id="video" width="100%" height="91%" poster="{{@@script@all##thumbnailUrl":\s*"([^"]+)"##$1##}}" controls autoplay muted loop></video>
<script>
    const video = document.getElementById('video');
    const sources = ${JSON.stringify(sources)};
    let hls = null;
    let currentSource = 0;

    // 检测是否为HLS格式
    function isHLS(url) {
        return url.includes('.m3u8') || url.includes('/playlist.m3u8');
    }

    // 播放视频源
    function playSource(url) {
        if (hls) {
            hls.destroy();
            hls = null;
        }

        if (isHLS(url)) {
            if (Hls.isSupported()) {
                hls = new Hls({
                    enableSoftwareAES: true,
                    maxBufferLength: 30,
                    maxMaxBufferLength: 60
                });
                hls.loadSource(url);
                hls.attachMedia(video);
                hls.on(Hls.Events.ERROR, function(event, data) {
                    if (data.fatal) switchToNextSource();
                });
            } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
                video.src = url;
            }
        } else {
            // MP4格式直接播放
            video.src = url;
        }
    }

    // 切换到下一个源
    function switchToNextSource() {
        if (sources.length <= 1) return;
        currentSource = (currentSource + 1) % sources.length;
        playSource(sources[currentSource]);
        updateButtons();
    }

    // 切换视频源
    function switchSource(index) {
        currentSource = index;
        playSource(sources[index]);
        updateButtons();
    }

    // 更新按钮状态
    function updateButtons() {
        document.querySelectorAll('.source-btn').forEach((btn, i) => {
            btn.classList.toggle('active', i === currentSource);
        });
    }

    // 绑定按钮事件
    document.addEventListener('click', function(e) {
        if (e.target.classList.contains('source-btn')) {
            switchSource(parseInt(e.target.dataset.index));
        }
    });

    // 错误处理和循环播放
    video.onerror = switchToNextSource;
    video.onended = function() {
        if (sources.length === 1) {
            video.currentTime = 0;
            video.play();
        } else {
            switchToNextSource();
        }
    };

    // 播放第一个源
    if (sources.length > 0) switchSource(0);
</script>
</div>
</body>  
</html>
`;

