var scriptContent = result.match(/<script>([\s\S]*?)<\/script>/)[1];
var decoded = eval(scriptContent.split('eval').join(''));

var fakeDoc = {write: function(h) { this.h = h; }};
eval(decoded.split('document').join('fakeDoc'));

var src = fakeDoc.h.match(/src="([^"]*)"/)[1];
var response = java.ajax(source.sourceUrl + src);

if (response && response.indexOf('eval(function(p,a,c,k,e,d)') === 0) {
    var innerDecoded = eval(response.split('eval').join(''));
    var fakeDoc2 = {write: function(h) { this.h = h; }};
    eval(innerDecoded.split('document').join('fakeDoc2'));
    result = fakeDoc2.h.match(/data-url="([^"]*)"/)[1];
} else {
    result = response;
}

// 定义所有视频源
//var sources = [`${result}`,`${play4}`];
var sources = [`${result}`];

// 生成源按钮
var sourceButtons = "";
if (sources.length > 1) {
    for (var i = 0; i < sources.length; i++) {
        sourceButtons += `<button class="source-btn" data-index="${i}">源${i+1}</button>`;
    }
}

result=`
<html>  
<head>  
<meta charset="utf-8">  
<meta name="viewport" content="width=device-width,initial-scale=1,minimum-scale=1,maximum-scale=1,user-scalable=no">
<meta name="referrer" content="never"/>
<script src="https://s4.zstatic.net/ajax/libs/hls.js/1.6.13/hls.min.js"></script>
<style>
html, body { text-align: center;margin: 0; padding: 0; width: 100%; overflow: hidden; }
.source-container { position: absolute; top: 23px; right: 1px; z-index: 10; display: flex; gap: 1px; }
.source-btn { color: #ff0; background: rgba(0,0,0,0.7); padding: 1px 5px; border-radius: 10px; font-size: 13px; border: none; cursor: pointer; }
.source-btn.active { color: red !important; }
</style>
</head>  
<body>  
<div class="container">
    <div class="title">{{@@h1@text##A片|日本AV}}</div>
    ${sources.length > 1 ? `<div class="source-container">${sourceButtons}</div>` : ''}
    <video id="video" width="100%" height="91%" controls autoplay muted loop></video>
<script>
    const video = document.getElementById('video');
    const sources = ${JSON.stringify(sources)};
    let hls = null;
    let currentSource = 0;

    // 初始化HLS播放
    function playHLS(url) {
        if (hls) hls.destroy();

        if (Hls.isSupported()) {
            hls = new Hls({
enableSoftwareAES: true, // 强制软件解密
forceKeyFrameOnDiscontinuity: true, // 关键帧恢复

enableWorker: true, // 启用Web Worker提升性能
lowLatencyMode: false, // 点播关闭低延迟模式
backBufferLength: 90, // 增加后缓冲长度，支持快速回退

maxBufferLength: 30,  // 最大缓冲区长度(秒)
maxMaxBufferLength: 60,   // 绝对最大缓冲区长度
maxBufferSize: 60 * 1000 * 1000,  // 缓冲区大小限制(60MB)
maxBufferHole: 0.5, // 减少缓冲区空洞容忍度

abrEwmaFastLive: 3.0,   // 快速ABR响应
abrEwmaSlowLive: 9.0, // 慢速ABR响应  
abrEwmaDefaultEstimate: 500000,  // 默认带宽估计(500kbps)
abrMaxWithRealBitrate: true, // 基于实际码率进行ABR
maxFragLookUpTolerance: 0.25, // 片段查找容差

fragLoadingMaxRetry: 6, // 片段加载重试次数
fragLoadingRetryDelay: 1000, // 片段加载重试延迟
manifestLoadingMaxRetry: 3, // 清单加载重试次数
levelLoadingMaxRetry: 4, // 级别加载重试次数
    });
            hls.loadSource(url);
            hls.attachMedia(video);
        } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
            video.src = url;
        }
    }

    // 切换视频源
    function switchSource(index) {
        currentSource = index;
        playHLS(sources[index]);
        updateButtons();
    }

    // 更新按钮状态
    function updateButtons() {
        document.querySelectorAll('.source-btn').forEach((btn, i) => {
            btn.classList.toggle('active', i === currentSource);
        });
    }

    // 绑定按钮事件
    document.querySelectorAll('.source-btn').forEach(btn => {
        btn.addEventListener('click', () => switchSource(parseInt(btn.dataset.index)));
    });

    // 播放第一个源
    if (sources.length > 0) switchSource(0);
</script>
<script src="https://s4.zstatic.net/ajax/libs/crypto-js/4.1.1/crypto-js.min.js"></script>
<script>
// 密钥配置
const KEY_STR = "102_53_100_57_54_53_100_102_55_53_51_51_54_50_55_48";
const IV_STR = "57_55_98_54_48_51_57_52_97_98_99_50_102_98_101_49";

const key = CryptoJS.enc.Utf8.parse(
  KEY_STR.split('_').map(c => String.fromCharCode(parseInt(c, 10))).join('')
);
const iv = CryptoJS.enc.Utf8.parse(
  IV_STR.split('_').map(c => String.fromCharCode(parseInt(c, 10))).join('')
);

// ArrayBuffer转Base64
async function ab2b64(buffer) {
  return new Promise(resolve => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result.split(',')[1]);
    reader.readAsDataURL(new Blob([buffer]));
  });
}

// 简化后的解密函数
async function decryptImageToBlob(url) {
  const response = await fetch(url, { mode: 'cors' });
  const buffer = await response.arrayBuffer();
  const base64Data = await ab2b64(buffer);

  const decrypted = CryptoJS.AES.decrypt(
    base64Data,
    key,
    { iv, mode: CryptoJS.mode.CBC, padding: CryptoJS.pad.Pkcs7 }
  );

  const decryptedBytes = new Uint8Array(
    decrypted.toString(CryptoJS.enc.Latin1)
      .split('')
      .map(c => c.charCodeAt(0))
  );

  return URL.createObjectURL(new Blob([decryptedBytes], { type: 'image/jpeg' }));
}

// 直接执行解密设置
window.addEventListener('DOMContentLoaded', () => {
  const video = document.getElementById('video');
  const originalPoster = "${java.get('pic')}";

  decryptImageToBlob(originalPoster).then(decryptedUrl => {
    video.poster = decryptedUrl;
  });
});
</script>
</div>
</body>  
</html>
`;

